I'm glad you're interested in creating a bot for entertainment recommendations! Here's a simple way to get started using Python and the Flask framework for the bot's backend. We'll use the Open Library API for book recommendations and the OMDB API for movie recommendations.

First, install the required libraries:

```bash
pip install flask requests
```

Now, create a file named `app.py` and add the following code:

```python
from flask import Flask, request, jsonify
import requests

app = Flask(__name__)

# Replace 'your_api_key' with your actual OMDB API key
OMDB_API_KEY = 'your_api_key'

@app.route('/recommend', methods=['POST'])
def recommend():
    data = request.get_json()
    category = data.get('category')
    title = data.get('title')

    if category == 'book':
        book_recommendation = get_book_recommendation(title)
        return jsonify({'recommendation': book_recommendation})
    elif category == 'movie':
        movie_recommendation = get_movie_recommendation(title)
        return jsonify({'recommendation': movie_recommendation})
    else:
        return jsonify({'error': 'Invalid category'}), 400

def get_book_recommendation(title):
    # Use Open Library API to get book recommendations
    url = f'https://openlibrary.org/search.json?q={title}'
    response = requests.get(url)
    data = response.json()
    if data['numFound'] > 0:
        book = data['docs'][0]
        return {
            'title': book.get('title'),
            'author': book.get('author_name', [])[0] if book.get('author_name') else 'Unknown',
            'first_publish_year': book.get('first_publish_year')
        }
    else:
        return 'No recommendations found.'

def get_movie_recommendation(title):
    # Use OMDB API to get movie recommendations
    url = f'http://www.omdbapi.com/?t={title}&apikey={OMDB_API_KEY}'
    response = requests.get(url)
    data = response.json()
    if data['Response'] == 'True':
        return {
            'title': data.get('Title'),
            'year': data.get('Year'),
            'director': data.get('Director'),
            'imdb_rating': data.get('imdbRating')
        }
    else:
        return 'No recommendations found.'
